'use client';

import * as React from 'react';
import { motion, useSpring, useMotionValue } from 'framer-motion';
import { Slot } from '@radix-ui/react-slot';
import { cn } from '@/lib/utils';

export const MagneticButton = React.forwardRef(({ className, asChild = false, intensity = 0.4, range = 50, ...props }, ref) => {
  const Comp = asChild ? Slot : 'button';
  const x = useMotionValue(0);
  const y = useMotionValue(0);
  const springX = useSpring(x, { stiffness: 180, damping: 20 });
  const springY = useSpring(y, { stiffness: 180, damping: 20 });

  const onMouseMove = (e) => {
    const { clientX, clientY, currentTarget } = e;
    const { left, top, width, height } = currentTarget.getBoundingClientRect();
    const centerX = left + width / 2;
    const centerY = top + height / 2;
    const diffX = clientX - centerX;
    const diffY = clientY - centerY;
    const dist = Math.sqrt(diffX ** 2 + diffY ** 2);
    if (dist < range) {
      x.set(diffX * intensity); y.set(diffY * intensity);
    } else {
      x.set(0); y.set(0);
    }
  };

  return (
    <motion.div style={{ x: springX, y: springY }} className="inline-block">
      <Comp
        ref={ref}
        className={cn("relative inline-flex items-center justify-center", className)}
        onMouseMove={onMouseMove}
        onMouseLeave={() => { x.set(0); y.set(0); }}
        {...props}
      />
    </motion.div>
  );
});
MagneticButton.displayName = "MagneticButton";
